/**
 * TODO: uzupełnij realne mapowanie agid -> group_slug z Google Ads.
 * resolveHeroVariant działa już bez tego dla keywordów i fallbacku globalnego.
 */
export const AGID_TO_GROUP: Record<string, keyof typeof GROUP_DEFAULTS> = {
  // "1234567890": "ogolne",
  // "1234567890": "warszawa",
  // "1234567890": "krakow",
  // "1234567890": "wroclaw",
  // "1234567890": "poznan",
  // "1234567890": "katowice",
  // "1234567890": "gdansk",
}

function normalizeParam(value?: string | string[]) {
  return decodeURIComponent(Array.isArray(value) ? value[0] ?? '' : value ?? '')
    .replace(/\+/g, ' ')
    .trim()
    .toLowerCase()
}

export function resolveHeroVariant(params: {
  kw?: string | string[]
  agid?: string | string[]
}): HeroVariant {
  const kw = normalizeParam(params.kw)
  const agid = normalizeParam(params.agid)
  const groupSlug = AGID_TO_GROUP[agid]

  return (
    (kw && KEYWORD_VARIANTS[kw]) ||
    (groupSlug && GROUP_DEFAULTS[groupSlug]) ||
    GLOBAL_DEFAULT
  )
}